{
  "title": "कंटेक्स्ट बजट",
  "group": "टोकन प्रबंधन",
  "options": [
    {
      "text": "कंटेक्स्ट विंडो का 95%+ उपयोग अधिकतम जानकारी के लिए करें"
    },
    {
      "text": "आउटपुट के लिए महत्वपूर्ण शेष जगह बचाएं बजाय पूरे विंडो को भरने के"
    },
    {
      "text": "कंटेक्स्ट बजट केवल 32K टोकन्स वाले मॉडल्स के लिए महत्वपूर्ण है"
    },
    {
      "text": "जब विंडो अतिप्रवाहित होती है तो मॉडल स्वचालित रूप से काट देता है"
    }
  ],
  "questionProse": [
    "जब एक RAG प्रॉम्प्ट बनाते हैं जिसमें पुनर्प्राप्त कंटेक्स्ट होता है, तो कंटेक्स्ट बजट के लिए एक अच्छा नियम है:"
  ],
  "explanationProse": [
    "**इनपुट और आउटपुट** के बीच कंटेक्स्ट विंडो साझा की जाती है। यदि आप इनपुट के लिए 90% उपयोग करते हैं, तो मॉडल के प्रतिक्रिया उत्पन्न करने के लिए विंडो का केवल 10% शेष रह जाता है — जो अक्सर कटौती या नुकसानप्रद आउटपुट का कारण बनता है।\n\nएक तर्कसंगत अनुमान: पहले अपने अपेक्षित आउटपुट आकार का निर्धारण करें, फिर शेष बजट के अंतर्गत अपने इनपुट को सुविधाजनक रूप से रखें। कई RAG कार्यों के लिए, इनपुट के लिए कुल कंटेक्स्ट विंडो का अधिकतम 60-70% उपयोग करें (सिस्टम प्रॉम्प्ट + इतिहास + पुनर्प्राप्त कंटेक्स्ट)। शेष को उत्पादन और सुरक्षा शेष के लिए छोड़ दें।\n\nइसके अतिरिक्त, मॉडल अपने कंटेक्स्ट विंडो के किनारों के पास खराब काम करते हैं — समझ और निर्देशों का पालन तब घटता है जब कंटेक्स्ट भर जाता है। 95% चलाना तकनीकी रूप से संभव है। यह 50% चलाने के अनुभव के बराबर नहीं है।"
  ]
}
